import React from 'react';
import {Pressable, Text, View} from 'react-native';
import {Gesture, GestureDetector} from 'react-native-gesture-handler';
import Animated, {useAnimatedStyle, useReducedMotion, useSharedValue, withSpring} from 'react-native-reanimated';
export function TwistGestureForCompassCalibrationGesture({onCommit}) {
  const reduceMotion = useReducedMotion();
  const x = useSharedValue(0);
  const pan = Gesture.Pan().activeOffsetX([-12,12]).onUpdate(e => { x.value = Math.max(-120, Math.min(120, e.translationX)); }).onEnd(() => { x.value = reduceMotion ? 0 : withSpring(0); });
  const style = useAnimatedStyle(() => ({transform:[{translateX:x.value}]}));
  return <View><GestureDetector gesture={pan}><Animated.View style={style}><Pressable accessibilityRole="button" accessibilityLabel="Twist gesture for compass calibration" accessibilityHint="Use the visible button if gestures are difficult" accessibilityActions={[{name:'activate',label:'Commit'}]} onAccessibilityAction={onCommit} hitSlop={{top:8,right:8,bottom:8,left:8}} style={{minHeight:44,minWidth:44}} onPress={onCommit}><Text>Twist gesture for compass calibration</Text></Pressable></Animated.View></GestureDetector></View>;
}

