  if (Platform.OS === 'ios') return <Pressable accessibilityRole="button" accessibilityLabel="Long-press app icon for quick actions (iOS)" hitSlop={{top:8,right:8,bottom:8,left:8}} onPress={() => ActionSheetIOS.showActionSheetWithOptions({options: [...options.map(o => o.label), 'Cancel'], cancelButtonIndex: options.length, destructiveButtonIndex: options.findIndex(o => o.destructive)}, i => { if (i < options.length) onSelect(options[i]); })}><Text>More</Text></Pressable>;
  return <Modal transparent animationType="slide" accessibilityViewIsModal onRequestClose={onDismiss}><Pressable accessibilityRole="button" accessibilityLabel="Dismiss menu" style={{flex:1}} onPress={onDismiss}/><View accessibilityRole="menu">{options.map(o => <Pressable key={o.key} accessibilityRole="menuitem" accessibilityLabel={o.label} style={{minHeight:48}} onPress={() => onSelect(o)}><Text>{o.label}</Text></Pressable>)}</View></Modal>;
}

