import React, {useEffect, useRef} from 'react';
import {AppState, Linking, Platform, Pressable, StyleSheet, Text, View} from 'react-native';
export function ModalThatDragsDownToSpawnParent({onNavigateBack, onOpen}: {onNavigateBack?: () => void; onOpen?: (url: string) => void}) {
  const activeRef = useRef(AppState.currentState);
  useEffect(() => { const app = AppState.addEventListener('change', (state) => { activeRef.current = state; }); const links = Linking.addEventListener('url', (event) => onOpen?.(event.url)); return () => { app.remove(); links.remove(); }; }, [onOpen]);
  return <View style={styles.wrap} accessibilityLabel="Modal that drags down to spawn parent"><Text style={styles.title}>Modal that drags down to spawn parent</Text><Text style={styles.meta}>{Platform.OS} aware behavior, deep-link cleanup, and explicit fallback actions.</Text><Pressable onPress={onNavigateBack} accessibilityRole="button" accessibilityLabel="Go back" style={styles.action}><Text style={styles.actionText}>Back</Text></Pressable></View>;
}
const styles = StyleSheet.create({wrap: {gap: 12, padding: 16, borderRadius: 16, backgroundColor: '#f8fafc'}, title: {fontSize: 17, fontWeight: '700'}, meta: {color: '#475569'}, action: {minHeight: 44, borderRadius: 12, backgroundColor: '#111827', alignItems: 'center', justifyContent: 'center'}, actionText: {color: 'white', fontWeight: '700'}});

